function solve(n: number, edges: number[][], label: string): number {
    const graph = new Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    let maxLen = 1;

    function isPalindrome(s: string[]): boolean {
        let left = 0;
        let right = s.length - 1;
        while (left < right) {
            if (s[left] !== s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    function dfs(node: number, visited: Set<number>, path: number[]): void {
        const currentLabels = path.map(x => label[x]);
        if (isPalindrome(currentLabels)) {
            maxLen = Math.max(maxLen, currentLabels.length);
        }

        for (const neighbor of graph[node]) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                path.push(neighbor);
                dfs(neighbor, visited, path);
                path.pop();
                visited.delete(neighbor);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        const visited = new Set<number>([i]);
        const path = [i];
        dfs(i, visited, path);
    }

    return maxLen;
}

