        var left = 0
        var right = s.size - 1
        while (left < right) {
            if (s[left] != s[right]) return false
            left++
            right--
        }
        return true
    }

    fun dfs(node: Int, visited: MutableSet<Int>, path: MutableList<Int>): Unit {
        val currentLabels = path.map { label[it] }.toTypedArray()
        if (isPalindrome(currentLabels)) {
            maxLen = maxOf(maxLen, currentLabels.size.toLong())
        }

        for (neighbor in graph[node]) {
            if (!visited.contains(neighbor)) {
                visited.add(neighbor)
                path.add(neighbor)
                dfs(neighbor, visited, path)
                path.removeLast()
                visited.remove(neighbor)
            }
        }
    }

    for (i in 0 until n.toInt()) {
        val visited = mutableSetOf<Int>().apply { add(i) }
        val path = mutableListOf<Int>().apply { add(i) }
        dfs(i, visited, path)
    }

    return maxLen
}
